var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_QM","text":{"KOREA":"마침 연락이 왔네.","JPN":"ちょうど今、連絡が来た。","ENG":"Oh, good timing. I got a call.","TWN":"正好有消息傳來。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L6_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"어떻게 됐지? 스완은 찾았나?","JPN":"どうなった？　スワンは見つかったか？","ENG":"What's going on? Did you find Swan?","TWN":"怎麼樣？找到史旺了嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L8_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"역시… 관리국이 보낸 요원이었군요.","JPN":"やはり……管理局のエージェントだったのですね。","ENG":"So he was an agent sent by the Administration... just as I thought.","TWN":"果然……是管理局派的人。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"관리국 시니어 르네. 당신에게 인사드리는 건 이번이 처음이겠네요.","JPN":"管理局シニア、ルネ。あなた方にご挨拶するのはこれが初めてになりますね。","ENG":"Renée, Senior of the Administration. I guess this is the first time we're talking.","TWN":"管理局Senior芮妮。這是我第一次向你問好。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"네가 왜 그 통신기를 가지고 있지? 스완?","JPN":"どうしてあなたが通信機を持っているんだ？　スワン。","ENG":"How come you have that comms device, Swan?","TWN":"你為什麼會有那個通訊器？史旺？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그런 뻔한 질문을 설명하려고 연락을 드린 건 아닙니다.","JPN":"そのような質問に答えるために連絡したのではありません。","ENG":"I didn't call you just to answer such an obvious question.","TWN":"我聯繫你並不是為了回答這麼簡單的問題。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"전 당신에게 도발이 아닌, 경고를 하고 싶은 거니까요.","JPN":"私はあなたに挑発ではなく、警告をしたいのです。","ENG":"I don't mean to provoke you. I mean to warn you.","TWN":"我想給你們一個警告，而不是挑釁。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"네가 나한테 경고를 한다고?","JPN":"あなたが、私に？","ENG":"\\"You\\" want to warn \\"me?\\"","TWN":"警告我？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"시니어의 죽음은 경고일 뿐이에요.","JPN":"シニアの死はただの警告です。","ENG":"The Senior's death was merely a warning.","TWN":"Senior的死只是一個警告。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"더 이상 절 쫓으려 한다면 그땐 당신도 무사하지 못할 겁니다.","JPN":"これ以上私を追うつもりなら、その時はあなたも無事では済みませんよ。","ENG":"You'll meet a similar fate if you keep coming after me.","TWN":"如果你再追我，連你自己也會陷入危險。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"사진을 퍼트린 게 너였군.","JPN":"写真をばら撒いたのはあなただったのだな。","ENG":"So it was you who spread the photo.","TWN":"原來就是你散播照片的。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"왜 이런 짓을 벌이는 거지? 지금껏 쌓아온 부와 명성을 전부 버릴 정도로 너에게 필요한 게 있나?","JPN":"なぜこんなことを？　今まで積み重ねてきた富と名声を捨てるほど、必要なものがあるのか？","ENG":"Why are you doing this? What's so important to you that you're willing to throw away all the wealth and fame you've achieved?","TWN":"你為什麼要這麼做？ 你是不是迫切需要什麼東西，以至於不惜拋棄一直以來累積的財富和名聲？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신도 알지 않나요? 샤레이드에서 부와 명성이란 건 쓰다 버릴 수단일 뿐이란 걸.","JPN":"あなたもわかっているのでは？　シャレードで富と名声というのは、利用して捨てる手段でしかないのです。","ENG":"I'm sure you're aware that wealth and fame are just a means to an end.","TWN":"你知道的，不是嗎？在查雷德，財富和名聲只不過是達到目的的手段。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그 대가로 얻고 싶은 게 고작 샤레이드가 혼란에 빠지는 꼴은 아니겠지?","JPN":"その対価で得たいものが、たかがシャレードの混乱だと言うのではあるまいな？","ENG":"And I doubt you're using them just to bring chaos to Charade.","TWN":"以那麼多財富和名聲為代價得到的只是讓查雷德陷入混亂？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"세피로트 나무.","JPN":"セフィロト。","ENG":"The Tree of Sephiroth.","TWN":"生命樹。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"옆에서 듣고 계신 분도 있을 테니, 힌트는 그 정도면 충분하겠죠.","JPN":"隣で聞いている方もいらっしゃるでしょうから、ヒントはこれで十分でしょう。","ENG":"That should be enough of a clue, considering the presence of the person listening next to you.","TWN":"這個提示應該足夠了吧？相信你們旁邊也有人在聽。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"네가 그걸 어떻게…?","JPN":"どうしてあなたがそれを……？","ENG":"How did you...?","TWN":"你怎麼會知道？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"모든 건 저의 각본대로 움직일 뿐입니다, 르네.","JPN":"すべては私の脚本通りに動くのです、ルネ。","ENG":"Everything is according to my script, Renée.","TWN":"一切都在按照我的劇本進行，芮妮。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신은 각본의 수많은 엑스트라들 중 하나지만…","JPN":"あなたは脚本の中、数多くのエキストラの一人にすぎませんが……","ENG":"You are one of many background characters of the script, but...","TWN":"你是劇本中眾多的臨時演員之一，但……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 사람은 이 무대를 처음부터 끝까지 지켜보는 관중이 되어야 하거든요.","JPN":"あの人にはこの舞台を最後まで見届ける観客になってもらわないと困るのですよ。","ENG":"He has to be a part of the audience and watch this performance from start to finish.","TWN":"那個人要擔任的是從頭到尾觀賞這個舞台表演的觀眾。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"모든 게 자기가 원하는대로 흘러갈 거라 생각하다니. 오만하군.","JPN":"すべてが自分の思い通りになると思うか。傲慢だな。","ENG":"Arrogant of you to think that everything would go according to your plan.","TWN":"你以為一切都會按你的想法發展，真是傲慢。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신도 그렇지 않나요?","JPN":"あなたもそうではありませんか？","ENG":"Aren't you the same?","TWN":"你不也是這樣嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"세상이 만든 법칙을 거스르고, 자신이 원하는 형태로 현실을 바꾸고 있는 걸요.","JPN":"世界が作った法則に逆らい、自身の望む形へと現実を変えているのですから。","ENG":"You're defying the rules made by this world and changing reality into the form you want it to be.","TWN":"你無視世界的法則，按照自己的喜好扭曲現實。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"흠, 나에게 이 정도로 관심을 갖는 팬이 있을 줄은 몰랐는데.","JPN":"ほう、これほど私に興味がある熱心なファンがいるとは知らなかったな。","ENG":"Hmm. I didn't know I had a fan who was interested in me like this.","TWN":"嗯，沒想到你竟然還是我的狂熱粉絲呢"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"맞아요. 전 당신의 열렬한 관중이자 팬입니다.","JPN":"そうです。私はあなたの熱烈な観客であり、ファンなのです。","ENG":"Yes. I am your biggest fan and audience.","TWN":"沒錯，我是你最忠實的觀眾和粉絲。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래서 언젠가 제 무대에 당신을 초청하고 싶었어요.","JPN":"いつかあなたを私の舞台に招待したかった。","ENG":"Which is why I was meaning to invite you to my performance one day.","TWN":"所以總有一天想把你邀請到我的舞台。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 마침내, 제가 준비한 각본을 실현할 기회가 온 셈이죠.","JPN":"そしてやっと今、私の準備した脚本を実現するチャンスが来たのです。","ENG":"And finally, I have the chance to carry out my script.","TWN":"而我終於迎來了實現自己寫的劇本的機會。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇게까지 해서 나에게 뭘 보여주고 싶은 거지?","JPN":"そこまでして私に見せたいものとは何かね？","ENG":"So, what are you trying to show me by going through all this?","TWN":"你費這麼大勁是想給我看什麼？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이 불가능하다 여겨 포기했던 일을… 실현해 보일 겁니다.","JPN":"あなたが不可能だと思い、諦めたことを……私が実現させてみせます。","ENG":"I will accomplish... what you deemed impossible and gave up on.","TWN":"你將實現……你認為不可能實現的事情。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그러니 부디, 당신이 이 극의 종장에 무사히 다다를 수 있기를…","JPN":"だから、どうかあなたがこの物語の終章に無事たどり着けるよう……","ENG":"So I sincerely hope you reach the finale of this play...","TWN":"所以，希望你能平安活到這個劇本的大結局……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"<color=#ffd34c>팬으로서 응원할게요.</color>","JPN":"<color=#ffd34c>ファンとして応援します。</color>","ENG":"<color=#ffd34c>As a fan.</color>","TWN":"<color=#ffd34c>我會作為粉絲為你加油。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>로터스</color> 대균열 지대","JPN":"管理局直轄都市<color=#ffd34c>ロータス</color>、大亀裂地帯","ENG":"Administration Direct Control City, <color=#ffd34c>Lotus</color>, Grand Dimension Crevice","TWN":"管理局直轄市<color=#ffd34c>洛德斯</color> 大峽谷地帶"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"마침내 이걸로 마지막이로군요.","JPN":"いよいよこれで最後ですね。","ENG":"Finally, this will be the last.","TWN":"終於，這就是最後一個了。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"<color=#ffd34c>이 세계 각지에 활성화된 여섯 곳의 대균열.</color>","JPN":"<color=#ffd34c>この世界各地で活性化した六か所の大亀裂。</color>","ENG":"<color=#ffd34c>The six Grand Dimension Crevices activated across the world.</color>","TWN":"<color=#ffd34c>在世界各地活躍的六處大峽谷中植入的碎片。</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"<color=#ffd34c>그 각각의 대균열에 암군이 멸망시킨 세계의 클리파 차원으로 통하는 거울 조각을 심어두는 것.</color>","JPN":"<color=#ffd34c>その大亀裂に暗君が滅亡させた世界のクリファ次元に通じる鏡の破片を仕込んでおくこと。</color>","ENG":"<color=#ffd34c>Planting a mirror fragment that leads to the Qlipha Dimension of the world destroyed by the Ignorant Monarch in each of the Grand Dimension Crevices.</color>","TWN":"<color=#ffd34c>每個鏡子碎片都通向著被暗軍毀滅的世界所化作的逆卡巴拉次元。</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇게 되면, 타기리온의 클리파 차원이 연결된 상태에서 방주의 봉인이 해제되는 순간.","JPN":"そうすれば、タギリオンのクリファ次元が繋がった状態で箱舟の封印が解除された瞬間、","ENG":"Alas, the moment when the Ark's seal is removed while linked to Thagirion's Qlipha Dimension.","TWN":"那樣的話，在塔基里翁的逆卡巴拉次元連接下，方舟的封印解除的那瞬間。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"나의 고향 런던이 그랬던 것처럼. 전 세계는 순식간에 마왕의 권능으로 휩싸이게 되겠죠.","JPN":"私の故郷、ロンドンのように、全世界は瞬時に魔王の権能で覆われることになるでしょう。","ENG":"Just like what happened in London. The entire world will suddenly be engulfed by the Demon Lord's power.","TWN":"如同我的故鄉倫敦一樣，全世界將瞬間被魔王的權能所籠罩。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 방주의 봉인을 여는 마지막 열쇠는 아마도…….","JPN":"そして箱舟の封印を解く最後の鍵はおそらく……","ENG":"And the last key to removing the Ark's seal is...","TWN":"而開啟方舟封印的最後一把鑰匙是……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"모든 것은 각본대로.","JPN":"すべては脚本どおりに。","ENG":"Everything according to the script.","TWN":"一切都將按照劇本進行。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"암군이여, 이걸로 계약은…….","JPN":"暗君よ、これで契約は……","ENG":"Oh, Ignorant Monarch. With this, the contract is...","TWN":"昏君啊，如此一來，我們的契約……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_QM","text":{"KOREA":"글쎄? 각본이 있는 경기 같은 건 조금 지루하지 않아?","JPN":"さあね？　脚本のある試合って、つまらないと思わない？","ENG":"Well, well, well. Don't you think matches fixed with a script are kind of boring?","TWN":"嗯？但你不覺得，拿著劇本的比賽會很無聊嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MARYJANE_SWANSONG_NPC_QM","text":{"KOREA":"승부에는 변수가 있어야 흥미로운 법이거든.","JPN":"変数があれば面白くなるわ。","ENG":"A game is interesting because of all the variables.","TWN":"比賽中有變數才有趣嘛。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"음?","JPN":"ん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그래, 그 카나리아 병아리들처럼 말이지.","JPN":"そう、あのカナリアのヒヨコたちのようにね。","ENG":"Yeah, like those Canary chicks.","TWN":"對，就像金絲雀的那些小鳥一樣。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"오지만……. 디아스……?","JPN":"オジマン……ディアス……？","ENG":"Ozyman... dias...?","TWN":"奧茲曼……迪亞斯……?"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"반가워, 스완.","JPN":"会えてうれしいわ、スワン。","ENG":"Nice to meet you, Swan.","TWN":"很高興見到你，史旺。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"이래봬도 네 팬이었다고. 사인이라도 부탁하고 싶은데~","JPN":"こう見えて私、あなたのファンなのよ。サインでも頼みたいところだけど～","ENG":"I'm a huge fan of you. So, I'd like to ask for your autograph, but...","TWN":"其實我是你的粉絲呢。真想要個簽名～"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"아무래도 지금은 조금 그러려나?","JPN":"今はちょっとあれかしら。","ENG":"I guess now's not a good time, right?","TWN":"不過現在好像有點不合適了吧？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","bgm":"NEW_WORLD_INST","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};